  request: ZuploRequest,
  context: ZuploContext,
) {
  const country = request.headers.get("cf-ipcountry");
  let upstream = "https://echo.zuplo.io/default";

  if (country === "US") {
    upstream = "https://echo.zuplo.io/us";
  } else if (country === "GB") {
    upstream = "https://echo.zuplo.io/gb";
  }

  return fetch(upstream, request);
}

